    label: "python compileall",
    argv: [
      ...pythonRunner.argv,
      "-m",
      "compileall",
      "-q",
      "-x",
      "(^|/)(\\.git|\\.opencode|node_modules|dist|build|out|venv|\\.venv|__pycache__)(/|$)",
      ".",
