def merge_start_here(existing: str, rendered: str) -> str:
    rendered_pattern = re.compile(
        rf"{re.escape(START_HERE_MANAGED_START)}[\s\S]*?{re.escape(START_HERE_MANAGED_END)}",
        re.MULTILINE,
    )
    rendered_match = rendered_pattern.search(rendered)
