function extractTomlSectionBody(text: string, section: string): string {
  const header = `[${section}]`
  const lines = text.split(/\r?\n/)
  const body: string[] = []
  let inSection = false
  for (const line of lines) {
    const trimmed = line.trim()
    if (!inSection) {
